# Deny-list rollout example: COUNT first
rule {
  name     = "geo-denylist-baseline"
  priority = 210

  action {
    count {}
  }

  statement {
    geo_match_statement {
      country_codes = ["RU", "KP"]
    }
  }

  visibility_config {
    cloudwatch_metrics_enabled = true
    metric_name                = "geoDenyListCount"
    sampled_requests_enabled   = true
  }
}

# Deny-list enforcement: switch COUNT -> BLOCK after validation
rule {
  name     = "geo-denylist-baseline"
  priority = 210

  action {
    block {}
  }

  statement {
    geo_match_statement {
      country_codes = ["RU", "KP"]
    }
  }

  visibility_config {
    cloudwatch_metrics_enabled = true
    metric_name                = "geoDenyListBlock"
    sampled_requests_enabled   = true
  }
}

# Allow-list rollout example: COUNT traffic outside approved countries
rule {
  name     = "geo-allowlist-baseline"
  priority = 211

  action {
    count {}
  }

  statement {
    not_statement {
      statement {
        geo_match_statement {
          country_codes = ["US", "CA", "GB"]
        }
      }
    }
  }

  visibility_config {
    cloudwatch_metrics_enabled = true
    metric_name                = "geoAllowListCount"
    sampled_requests_enabled   = true
  }
}
